    it('uses fallback Chinese message for 409 with no server message', async () => {
      globalThis.fetch = vi.fn().mockResolvedValue(
        mockResponse(409, {}),
      );

      const client = createClient();
      try {
        await client.post('/api/tasks/TASK-1/claim', { assignee: 'agent-beta' });
